            'files' => [
                'index.html' => "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Calculator</title>\n    <link rel=\"stylesheet\" href=\"style.css\">\n</head>\n<body>\n    <div class=\"calculator\">\n        <div class=\"display\">\n            <div class=\"display-value\">0</div>\n        </div>\n        \n        <div class=\"buttons\">\n            <button class=\"btn btn-clear\" onclick=\"clearDisplay()\">C</button>\n            <button class=\"btn btn-operator\" onclick=\"appendToDisplay('/')\">/</button>\n            <button class=\"btn btn-operator\" onclick=\"appendToDisplay('*')\">×</button>\n            <button class=\"btn btn-delete\" onclick=\"deleteLast()\">←</button>\n            \n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('7')\">7</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('8')\">8</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('9')\">9</button>\n            <button class=\"btn btn-operator\" onclick=\"appendToDisplay('-')\">-</button>\n            \n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('4')\">4</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('5')\">5</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('6')\">6</button>\n            <button class=\"btn btn-operator\" onclick=\"appendToDisplay('+')\">+</button>\n            \n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('1')\">1</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('2')\">2</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('3')\">3</button>\n            <button class=\"btn btn-equals\" onclick=\"calculate()\" rowspan=\"2\">=</button>\n            \n            <button class=\"btn btn-number btn-zero\" onclick=\"appendToDisplay('0')\">0</button>\n            <button class=\"btn btn-number\" onclick=\"appendToDisplay('.')\">.</button>\n        </div>\n    </div>\n    \n    <script src=\"script.js\"></script>\n</body>\n</html>",
                'style.css' => "body {\n    display: flex;\n    justify-content: center;\n    align-items: center;\n    min-height: 100vh;\n    margin: 0;\n    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n    font-family: 'Arial', sans-serif;\n}\n\n.calculator {\n    background: #2d3748;\n    border-radius: 20px;\n    padding: 30px;\n    box-shadow: 0 20px 40px rgba(0,0,0,0.3);\n    max-width: 400px;\n    width: 100%;\n}\n\n.display {\n    background: #1a202c;\n    border-radius: 10px;\n    padding: 20px;\n    margin-bottom: 20px;\n    text-align: right;\n}\n\n.display-value {\n    font-size: 3rem;\n    color: #fff;\n    font-weight: 300;\n    word-wrap: break-word;\n    word-break: break-all;\n}\n\n.buttons {\n    display: grid;\n    grid-template-columns: repeat(4, 1fr);\n    gap: 10px;\n}\n\n.btn {\n    border: none;\n    border-radius: 10px;\n    padding: 20px;\n    font-size: 1.5rem;\n    cursor: pointer;\n    transition: all 0.3s ease;\n    font-weight: 600;\n}\n\n.btn:hover {\n    transform: translateY(-2px);\n}\n\n.btn:active {\n    transform: translateY(0);\n}\n\n.btn-number {\n    background: #4a5568;\n    color: white;\n}\n\n.btn-number:hover {\n    background: #718096;\n}\n\n.btn-operator {\n    background: #ed8936;\n    color: white;\n}\n\n.btn-operator:hover {\n    background: #f6ad55;\n}\n\n.btn-equals {\n    background: #48bb78;\n    color: white;\n    grid-row: span 2;\n}\n\n.btn-equals:hover {\n    background: #68d391;\n}\n\n.btn-clear {\n    background: #e53e3e;\n    color: white;\n}\n\n.btn-clear:hover {\n    background: #fc8181;\n}\n\n.btn-delete {\n    background: #9f7aea;\n    color: white;\n}\n\n.btn-delete:hover {\n    background: #b794f4;\n}\n\n.btn-zero {\n    grid-column: span 2;\n}\n\n@media (max-width: 480px) {\n    .calculator {\n        margin: 20px;\n        padding: 20px;\n    }\n    \n    .btn {\n        padding: 15px;\n        font-size: 1.2rem;\n    }\n    \n    .display-value {\n        font-size: 2rem;\n    }\n}",
                'script.js' => "let display = document.querySelector('.display-value');\nlet currentInput = '0';\nlet shouldResetDisplay = false;\n\nfunction updateDisplay() {\n    display.textContent = currentInput;\n}\n\nfunction clearDisplay() {\n    currentInput = '0';\n    updateDisplay();\n}\n\nfunction appendToDisplay(value) {\n    if (shouldResetDisplay) {\n        currentInput = '0';\n        shouldResetDisplay = false;\n    }\n    \n    if (currentInput === '0' && value !== '.') {\n        currentInput = value;\n    } else {\n        currentInput += value;\n    }\n    \n    updateDisplay();\n}\n\nfunction deleteLast() {\n    if (currentInput.length > 1) {\n        currentInput = currentInput.slice(0, -1);\n    } else {\n        currentInput = '0';\n    }\n    updateDisplay();\n}\n\nfunction calculate() {\n    try {\n        // Replace display multiplication symbol with JavaScript operator\n        let expression = currentInput.replace(/×/g, '*');\n        \n        // Basic safety check\n        if (!/^[0-9+\\-*/.\\s]+$/.test(expression)) {\n            throw new Error('Invalid expression');\n        }\n        \n        let result = eval(expression);\n        \n        // Handle decimal places\n        if (!Number.isInteger(result)) {\n            result = Math.round(result * 100000000) / 100000000; // Round to 8 decimal places\n        }\n        \n        currentInput = result.toString();\n        shouldResetDisplay = true;\n        updateDisplay();\n    } catch (error) {\n        currentInput = 'Error';\n        shouldResetDisplay = true;\n        updateDisplay();\n        \n        setTimeout(() => {\n            clearDisplay();\n        }, 2000);\n    }\n}\n\n// Keyboard support\ndocument.addEventListener('keydown', function(event) {\n    const key = event.key;\n    \n    if (key >= '0' && key <= '9') {\n        appendToDisplay(key);\n    } else if (key === '.') {\n        appendToDisplay('.');\n    } else if (key === '+' || key === '-' || key === '*' || key === '/') {\n        appendToDisplay(key === '*' ? '×' : key);\n    } else if (key === 'Enter' || key === '=') {\n        calculate();\n    } else if (key === 'Escape' || key === 'c' || key === 'C') {\n        clearDisplay();\n    } else if (key === 'Backspace') {\n        deleteLast();\n    }\n});\n\n// Initialize display\nupdateDisplay();"
            ]
        ]
    ];
}

// Handle template requests
if ($_SERVER['REQUEST_METHOD'] === 'GET') {
    header('Content-Type: application/json');
    
    $action = $_GET['action'] ?? '';
    
    switch ($action) {
        case 'get_templates':
            echo json_encode(['success' => true, 'templates' => getProjectTemplates()]);
            break;
            
        default:
            echo json_encode(['success' => false, 'error' => 'Invalid action']);
    }
    exit();
}
